      {"type":"multi-select","question":"Признаки переполнения контекста?","options":[{"id":"a","text":"Claude повторяется","correct":True},{"id":"b","text":"Забывает ранние инструкции","correct":True},{"id":"c","text":"Ответы менее точные","correct":True},{"id":"d","text":"Claude работает быстрее","correct":False},{"id":"e","text":"Появляется сообщение об автокомпрессии","correct":True}]},
