      {"type":"quiz","question":"Какая команда сжимает контекст без потери важной информации?","options":[{"id":"a","text":"/compact","correct":True},{"id":"b","text":"/clear","correct":False},{"id":"c","text":"/reset","correct":False},{"id":"d","text":"/compress","correct":False}]},
