      {"type":"matching","pairs":[{"left":"Read-only задачи","right":"Explore субагент (быстрее)"},{"left":"Запись/реализация","right":"General субагент"},{"left":"Большой рефакторинг","right":"Planner + Executors"},{"left":"Новая фича + тесты","right":"Coder + Tester"}]},
